let results = [];

for (const item of $input.all()) {
    for (key of Object.keys(item.binary)) {
        results.push({
            json: {
                fileName: item.binary[key].fileName,
                id: item.json.id
            },
            binary: {
                data: item.binary[key],
            }
        });
    }
}

return results;

